import React, { useState, useEffect } from 'react';
import CouponGenerator from './CouponGenerator';

const AdminPanel = () => {
  const [activeTab, setActiveTab] = useState('coupons');
  const [stats, setStats] = useState({});

  useEffect(() => {
    loadStats();
  }, []);

  const loadStats = () => {
    const coupons = JSON.parse(localStorage.getItem('adminCoupons') || '[]');
    const purchases = JSON.parse(localStorage.getItem('squarePurchases') || '{}');
    
    setStats({
      totalCoupons: coupons.length,
      activeCoupons: coupons.filter(c => !c.expiresAt || new Date(c.expiresAt) > new Date()).length,
      totalPurchases: Object.keys(purchases).length,
      revenue: Object.values(purchases).reduce((sum, p) => sum + (p.amount || 0), 0)
    });
  };

  return (
    <div className="admin-panel">
      <div className="admin-header">
        <h1>🎯 Admin Dashboard</h1>
        <p>Manage your advertising platform</p>
      </div>

      <div className="admin-stats">
        <div className="stat-card">
          <h3>{stats.totalCoupons}</h3>
          <p>Total Coupons</p>
        </div>
        <div className="stat-card">
          <h3>{stats.activeCoupons}</h3>
          <p>Active Coupons</p>
        </div>
        <div className="stat-card">
          <h3>{stats.totalPurchases}</h3>
          <p>Total Ads Sold</p>
        </div>
        <div className="stat-card">
          <h3>£{stats.revenue}</h3>
          <p>Total Revenue</p>
        </div>
      </div>

      <div className="admin-tabs">
        <button 
          className={activeTab === 'coupons' ? 'active' : ''}
          onClick={() => setActiveTab('coupons')}
        >
          🎫 Coupon Generator
        </button>
        <button 
          className={activeTab === 'analytics' ? 'active' : ''}
          onClick={() => setActiveTab('analytics')}
        >
          📊 Analytics
        </button>
      </div>

      <div className="admin-content">
        {activeTab === 'coupons' && <CouponGenerator />}
        {activeTab === 'analytics' && (
          <div className="analytics-tab">
            <h3>Platform Analytics</h3>
            <p>Coming soon: Detailed analytics dashboard</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;
